@dataclass
class KernelStats:
    """Performance statistics for a single kernel execution."""
    name: str
    optimization_level: int
    simulated_cycles: int = 0
    global_memory_loads: int = 0
    global_memory_stores: int = 0
    shared_memory_loads: int = 0
    shared_memory_stores: int = 0
    arithmetic_ops: int = 0
    threads_launched: int = 0
    blocks_launched: int = 0
    block_size: int = 0
    occupancy: float = 0.0

    @property
    def arithmetic_intensity(self) -> float:
        """FLOPs per byte of global memory traffic."""
        total_bytes = (self.global_memory_loads + self.global_memory_stores) * 4  # 4 bytes per float
        if total_bytes == 0:
            return float('inf')
        return self.arithmetic_ops / total_bytes

    @property
    def achieved_gflops(self) -> float:
        """Simulated GFLOP/s assuming 1 GHz clock."""
        if self.simulated_cycles == 0:
            return 0.0
        return self.arithmetic_ops / self.simulated_cycles  # ops per cycle (at 1 GHz = GFLOP/s)


@dataclass
class RooflineModel:
    """Roofline model for the GPU simulator."""
    peak_gflops: float          # Peak compute throughput
    peak_memory_bw_gb_s: float  # Peak memory bandwidth in GB/s

    def theoretical_peak(self, arithmetic_intensity: float) -> float:
        """Return the roofline ceiling for a given arithmetic intensity."""
        return min(self.peak_gflops, arithmetic_intensity * self.peak_memory_bw_gb_s)

    def is_compute_bound(self, arithmetic_intensity: float) -> bool:
        """True if the kernel is compute-bound at this arithmetic intensity."""
        ridge_point = self.peak_gflops / self.peak_memory_bw_gb_s
        return arithmetic_intensity >= ridge_point


class OptimizationHarness:
    """Manages the progressive optimization of a GPU kernel."""

    def __init__(self, algorithm_name: str, reference_fn: Callable, roofline: RooflineModel):
        self.algorithm_name = algorithm_name
        self.reference_fn = reference_fn  # CPU reference implementation
        self.roofline = roofline
        self.optimization_levels: list[dict] = []
        self.stats_history: list[KernelStats] = []

    def register_optimization(self, level: int, name: str, description: str,
                               kernel_fn: Callable, expected_improvement: str):
        """Register a new optimization level."""
        self.optimization_levels.append({
            'level': level,
            'name': name,
            'description': description,
            'kernel_fn': kernel_fn,
            'expected_improvement': expected_improvement,
        })

    def verify_correctness(self, gpu_output: list[float], reference_output: list[float],
                           tolerance: float = 1e-6) -> bool:
        """Verify GPU output matches CPU reference within relative tolerance."""
        if len(gpu_output) != len(reference_output):
            return False
        for gpu_val, ref_val in zip(gpu_output, reference_output):
            if ref_val == 0:
                if abs(gpu_val) > tolerance:
                    return False
            elif abs(gpu_val - ref_val) / abs(ref_val) > tolerance:
                return False
        return True

    def run_all_levels(self, test_input: list[float]) -> list[KernelStats]:
        """Run all optimization levels, verify correctness, collect stats."""
        reference_output = self.reference_fn(test_input)
        results = []
        for opt in sorted(self.optimization_levels, key=lambda x: x['level']):
            # TODO: Run kernel, collect stats, verify correctness
            # stats = opt['kernel_fn'](test_input)
            # assert self.verify_correctness(stats.output, reference_output)
            # results.append(stats)
            pass
        self.stats_history = results
        return results

    def compute_speedups(self) -> list[dict]:
        """Compute speedup of each level relative to baseline and previous level."""
        if not self.stats_history:
            return []
        baseline = self.stats_history[0].simulated_cycles
        speedups = []
        for i, stats in enumerate(self.stats_history):
            prev = self.stats_history[i - 1].simulated_cycles if i > 0 else baseline
            speedups.append({
                'level': stats.optimization_level,
                'name': stats.name,
                'speedup_vs_baseline': baseline / max(1, stats.simulated_cycles),
                'speedup_vs_previous': prev / max(1, stats.simulated_cycles),
                'arithmetic_intensity': stats.arithmetic_intensity,
                'achieved_gflops': stats.achieved_gflops,
                'roofline_ceiling': self.roofline.theoretical_peak(stats.arithmetic_intensity),
                'roofline_efficiency': (
                    stats.achieved_gflops /
                    max(1e-9, self.roofline.theoretical_peak(stats.arithmetic_intensity))
                ),
            })
        return speedups

    def generate_report_data(self) -> dict:
        """Generate structured data for the analysis report."""
        return {
            'algorithm': self.algorithm_name,
            'num_optimizations': len(self.optimization_levels),
            'speedups': self.compute_speedups(),
            'roofline': {
                'peak_gflops': self.roofline.peak_gflops,
                'peak_bw_gb_s': self.roofline.peak_memory_bw_gb_s,
                'ridge_point': self.roofline.peak_gflops / self.roofline.peak_memory_bw_gb_s,
            },
            'optimization_descriptions': [
                {'level': o['level'], 'name': o['name'], 'description': o['description']}
                for o in self.optimization_levels
            ],
        }

