@dataclass
class Node:
    """A compute node or switch in the network."""
    node_id: int
    is_switch: bool = False
    group_id: int = 0       # For dragonfly: which group this node belongs to
    coordinates: tuple = ()  # For torus: (x, y, z) position
    neighbors: list = field(default_factory=list)  # List of (neighbor_id, link_id)


@dataclass
class Link:
    """A bidirectional link between two nodes."""
    link_id: int
    node_a: int
    node_b: int
    bandwidth: float = 25.0   # GB/s per direction (e.g., Slingshot-11)
    latency_ns: float = 100.0 # Per-hop latency in nanoseconds


@dataclass
class LatencyModel:
    """Network latency model: total = alpha + beta * msg_size + gamma * hops."""
    alpha: float = 1000.0    # Startup latency (nanoseconds)
    beta: float = 0.004      # Per-byte transfer time (ns/byte) -> ~250 GB/s effective
    gamma: float = 100.0     # Per-hop latency (nanoseconds)

    def compute_latency(self, message_size_bytes: int, num_hops: int) -> float:
        """Compute total message latency in nanoseconds."""
        return self.alpha + self.beta * message_size_bytes + self.gamma * num_hops


@dataclass
class CongestionRecord:
    """Per-link congestion tracking."""
    link_id: int
    total_bytes_transferred: int = 0
    num_messages: int = 0
    peak_utilization: float = 0.0  # Fraction of bandwidth used at peak
    time_congested_ns: float = 0.0 # Total time utilization > threshold


class Topology(ABC):
    """Abstract base class for network topologies."""

    def __init__(self, num_compute_nodes: int = 1024):
        self.num_compute_nodes = num_compute_nodes
        self.nodes: dict[int, Node] = {}
        self.links: dict[int, Link] = {}
        self._next_node_id = 0
        self._next_link_id = 0

    @abstractmethod
    def build(self):
        """Construct the topology: create all nodes, switches, and links."""
        pass

    @abstractmethod
    def get_route(self, src: int, dst: int, adaptive: bool = False) -> list[int]:
        """Return a list of link IDs forming a path from src to dst.
        If adaptive=True, may choose among multiple paths to avoid congestion."""
        pass

    def _add_node(self, is_switch: bool = False, group_id: int = 0,
                  coordinates: tuple = ()) -> int:
        node_id = self._next_node_id
        self._next_node_id += 1
        self.nodes[node_id] = Node(
            node_id=node_id, is_switch=is_switch,
            group_id=group_id, coordinates=coordinates
        )
        return node_id

    def _add_link(self, node_a: int, node_b: int,
                  bandwidth: float = 25.0, latency_ns: float = 100.0) -> int:
        link_id = self._next_link_id
        self._next_link_id += 1
        self.links[link_id] = Link(
            link_id=link_id, node_a=node_a, node_b=node_b,
            bandwidth=bandwidth, latency_ns=latency_ns
        )
        self.nodes[node_a].neighbors.append((node_b, link_id))
        self.nodes[node_b].neighbors.append((node_a, link_id))
        return link_id

    @property
    def compute_nodes(self) -> list[int]:
        return [nid for nid, n in self.nodes.items() if not n.is_switch]

    @property
    def num_switches(self) -> int:
        return sum(1 for n in self.nodes.values() if n.is_switch)

    @property
    def num_links(self) -> int:
        return len(self.links)

    def diameter(self) -> int:
        """Compute network diameter (max shortest path between any two compute nodes)."""
        max_hops = 0
        for src in self.compute_nodes:
            distances = self._bfs_distances(src)
            for dst in self.compute_nodes:
                if dst != src and dst in distances:
                    max_hops = max(max_hops, distances[dst])
        return max_hops

    def average_path_length(self) -> float:
        """Compute average shortest path length between all compute node pairs."""
        total_hops = 0
        count = 0
        for src in self.compute_nodes:
            distances = self._bfs_distances(src)
            for dst in self.compute_nodes:
                if dst != src and dst in distances:
                    total_hops += distances[dst]
                    count += 1
        return total_hops / max(1, count)

    def _bfs_distances(self, src: int) -> dict[int, int]:
        """BFS from src, returning {node_id: distance} for all reachable nodes."""
        distances = {src: 0}
        queue = deque([src])
        while queue:
            current = queue.popleft()
            for neighbor_id, _ in self.nodes[current].neighbors:
                if neighbor_id not in distances:
                    distances[neighbor_id] = distances[current] + 1
                    queue.append(neighbor_id)
        return distances


