class MPICollective(ABC):
    """Base class for MPI collective operations."""

    def __init__(self, topology: Topology, latency_model: LatencyModel):
        self.topology = topology
        self.latency_model = latency_model
        self.messages_sent: list[dict] = []  # Log of all messages

    @abstractmethod
    def execute(self, message_size_bytes: int) -> dict:
        """Execute the collective and return performance metrics."""
        pass

    def _send_message(self, src: int, dst: int, size_bytes: int) -> float:
        """Send a message from src to dst. Return latency in nanoseconds."""
        route = self.topology.get_route(src, dst)
        num_hops = len(route)
        latency = self.latency_model.compute_latency(size_bytes, num_hops)
        self.messages_sent.append({
            'src': src, 'dst': dst, 'size_bytes': size_bytes,
            'num_hops': num_hops, 'latency_ns': latency,
            'links_used': route,
        })
        return latency


