class CongestionTracker:
    """Track per-link utilization and identify bottlenecks."""

    def __init__(self, topology: Topology, congestion_threshold: float = 0.8):
        self.topology = topology
        self.threshold = congestion_threshold
        self.records: dict[int, CongestionRecord] = {
            lid: CongestionRecord(link_id=lid) for lid in topology.links
        }

    def record_message(self, link_ids: list[int], message_size_bytes: int):
        """Record a message traversing a set of links."""
        for lid in link_ids:
            self.records[lid].total_bytes_transferred += message_size_bytes
            self.records[lid].num_messages += 1

    def get_bottleneck_links(self, top_n: int = 10) -> list[CongestionRecord]:
        """Return the top_n most utilized links."""
        return sorted(
            self.records.values(),
            key=lambda r: r.total_bytes_transferred,
            reverse=True
        )[:top_n]

    def utilization_summary(self) -> dict:
        """Summary statistics of link utilization."""
        if not self.records:
            return {}
        bytes_list = [r.total_bytes_transferred for r in self.records.values()]
        return {
            'max_bytes': max(bytes_list),
            'min_bytes': min(bytes_list),
            'mean_bytes': sum(bytes_list) / len(bytes_list),
            'std_bytes': (
                sum((b - sum(bytes_list) / len(bytes_list)) ** 2 for b in bytes_list)
                / len(bytes_list)
            ) ** 0.5,
            'num_congested_links': sum(
                1 for b in bytes_list if b > self.threshold * max(bytes_list)
            ),
            'total_links': len(bytes_list),
        }
